import os
from google.cloud import storage

def process_image(event, context):
    bucket_name = event['bucket']
    file_name = event['name']

    # Extract conversion options from metadata
    conversion_options = event.get('conversionOptions', [])

    # Construct the full path to the image in Cloud Storage
    object_path = os.path.join(bucket_name, file_name)

    # Get a reference to the bucket and blob
    client = storage.Client()
    bucket = client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    # Download the image from Cloud Storage
    blob.download_to_filename(file_name)

    # Construct the convert command with options
    cmd = f"convert {file_name} {' '.join(conversion_options)} output_{file_name}"

    # Run the convert command using subprocess.call()
    try:
        subprocess.call(cmd, shell=True)
    except Exception as e:
        print(f"Error processing image: {e}")

    # Upload the converted image back to Cloud Storage
    bucket.blob(f"output_{file_name}").upload_from_filename(file_name)

    # Clean up by deleting the original and converted images
    os.remove(file_name)